Table.Command:
( SELECT T0."AbsEntry", T0."BaseObject", T1."DocNum", T1."CardCode", T1."CardName", T1."ShipToCode", T1."Address2", T2."WhsCode", T3."AddID", T2."ItemCode", T2."Dscription" AS "ItemName", T2."Quantity", T2."OpenQty", T0."RelQtty", T0."PickQtty", T2."ShipDate", T5."OnHand", T4."NumInSale", T4."SalUnitMsr" FROM PKL1 T0 INNER JOIN ORDR T1 ON T0."OrderEntry" = T1."DocEntry" AND T0."BaseObject" = 17 LEFT OUTER JOIN RDR1 T2 ON T0."OrderEntry" = T2."DocEntry" AND T2."LineNum" = T0."OrderLine" LEFT OUTER JOIN OCRD T3 ON T1."CardCode" = T3."CardCode" LEFT OUTER JOIN OITM T4 ON T2."ItemCode" = T4."ItemCode" LEFT OUTER JOIN OITW T5 ON T5."ItemCode" = T2."ItemCode" AND T2."WhsCode" = T5."WhsCode" WHERE T0."AbsEntry" = {?DocKey@}
UNION ALL
SELECT T0."AbsEntry", T0."BaseObject", T1."DocNum", T1."CardCode", T1."CardName", T1."ShipToCode", T1."Address2", T2."WhsCode", T3."AddID", T2."ItemCode", T2."Dscription" AS "ItemName", T2."Quantity", T2."OpenQty", T0."RelQtty", T0."PickQtty", T2."ShipDate", T5."OnHand", T4."NumInSale", T4."SalUnitMsr" FROM PKL1 T0 INNER JOIN OINV T1 ON T0."OrderEntry" = T1."DocEntry" AND T0."BaseObject" = 13 LEFT OUTER JOIN INV1 T2 ON T0."OrderEntry" = T2."DocEntry" AND T2."LineNum" = T0."OrderLine" LEFT OUTER JOIN OCRD T3 ON T1."CardCode" = T3."CardCode" LEFT OUTER JOIN OITM T4 ON T2."ItemCode" = T4."ItemCode" LEFT OUTER JOIN OITW T5 ON T5."ItemCode" = T2."ItemCode" AND T2."WhsCode" = T5."WhsCode" WHERE T0."AbsEntry" = {?DocKey@}
UNION ALL
SELECT T0."AbsEntry", T0."BaseObject", T1."DocNum", T1."CardCode", T3."CardName", '' AS "ShipToCode", '' AS "Address2", T2."wareHouse" AS "WhsCode", T3."AddID", T2."ItemCode", T4."ItemName" AS "ItemName", T2."PlannedQty" AS "Quantity", T2."PlannedQty" AS "OpenQty", T0."RelQtty", T0."PickQtty", T1."DueDate" AS "ShipDate", T5."OnHand", T4."NumInSale", T4."SalUnitMsr" FROM PKL1 T0 INNER JOIN OWOR T1 ON T0."OrderEntry" = T1."DocEntry" AND T0."BaseObject" = 202 LEFT JOIN WOR1 T2 ON T0."OrderEntry" = T2."DocEntry" AND T2."LineNum" = T0."OrderLine" LEFT JOIN OCRD T3 ON T1."CardCode" = T3."CardCode" LEFT JOIN OITM T4 ON T2."ItemCode" = T4."ItemCode" LEFT JOIN OITW T5 ON T5."ItemCode" = T2."ItemCode" AND T2."wareHouse" = T5."WhsCode" WHERE T0."AbsEntry" = {?DocKey@}
UNION ALL
SELECT T0."AbsEntry", T0."BaseObject", T1."DocNum", T1."CardCode", T1."CardName", T1."ShipToCode", T1."Address2", T2."WhsCode", T3."AddID", T2."ItemCode", T2."Dscription" AS "ItemName", T2."Quantity", T2."OpenQty", T0."RelQtty", T0."PickQtty", T2."ShipDate", T5."OnHand", T4."NumInSale", T4."SalUnitMsr" FROM PKL1 T0 INNER JOIN OWTQ T1 ON T0."OrderEntry" = T1."DocEntry" AND T0."BaseObject" = 1250000001 LEFT JOIN WTQ1 T2 ON T0."OrderEntry" = T2."DocEntry" AND T2."LineNum" = T0."OrderLine" LEFT JOIN OCRD T3 ON T1."CardCode" = T3."CardCode" LEFT JOIN OITM T4 ON T2."ItemCode" = T4."ItemCode" LEFT JOIN OITW T5 ON T5."ItemCode" = T2."ItemCode" AND T2."WhsCode" = T5."WhsCode" WHERE T0."AbsEntry" = {?DocKey@} ) ORDER BY T2."ItemCode"

SectionAreaConditionFormulas.BackgroundColor:
// This conditional formatting formula must return one of the following Color Constants:
// 
// Color (red, green, blue)
// crBlack
// crMaroon
// crGreen
// crOlive
// crNavy
// crPurple
// crTeal
// crSilver
// crRed
// crLime
// crYellow
// crBlue
// crFuchsia
// crAqua
// crWhite
// crNoColor
// 
IF Recordnumber MOD 2 = 0 THEN
crSilver
ELSE
crNocolor
